// ---------------------------------------------------------------------------
// Category mapping
// ---------------------------------------------------------------------------

const ATTRACTION_CATS = new Set([
  'Attraction', 'Monastery', 'Historic', 'Monument', 'Natural Wonder',
  'Beach', 'Island', 'Nature', 'Mountain Pass', 'Temple', 'Village',
  'Wildlife', 'Cultural Experience', 'Hill Station', 'Lake', 'Gardens',
  'Meadow', 'Viewpoint', 'City', 'Shopping',
]);
const ACTIVITY_CATS = new Set([
  'Activity', 'Adventure', 'Wellness', 'Restaurant', 'Cafe', 'Café',
]);
const STAY_CATS = new Set([
  'Resort', 'Hotel', 'Homestay', 'Accommodation',
]);

function mapCategory(rawCategory) {
  if (STAY_CATS.has(rawCategory)) return 'stay';
  if (ACTIVITY_CATS.has(rawCategory)) return 'activity';
  // Default everything else to attraction
  return 'attraction';
}

function mapCostLevel(priceLevel) {
  switch (priceLevel) {
    case 'Free': return 'free';
    case '\u20B9': return 'budget';      // ₹
    case '\u20B9\u20B9': return 'moderate';  // ₹₹
    case '\u20B9\u20B9\u20B9': return 'premium';  // ₹₹₹
    default: return 'moderate';
  }
}

function popularityFromRating(rating) {
  // 4.9 -> 100, 4.8 -> 90, ... 4.0 -> 10, below -> 5
  if (rating >= 4.9) return 100;
  if (rating >= 4.0) return Math.round((rating - 4.0) * 100);
  return 5;
}

function slugify(text) {
  return text
    .toLowerCase()
    .replace(/&/g, 'and')
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/(^-|-$)/g, '');
}

/**
 * Parse an openHours string like "6:00 AM - 6:00 PM" into
 * { open: "06:00:00", close: "18:00:00", notes: null }
 * Returns { notes: raw } when it can't be parsed.
 */
function parseOperatingHours(raw) {
  if (!raw) return null;

  const timeRe = /(\d{1,2}:\d{2})\s*(AM|PM)\s*-\s*(\d{1,2}:\d{2})\s*(AM|PM)/i;
  const m = raw.match(timeRe);
  if (!m) return { notes: raw };

  function to24(t, ampm) {
    let [h, min] = t.split(':').map(Number);
    if (ampm.toUpperCase() === 'PM' && h !== 12) h += 12;
    if (ampm.toUpperCase() === 'AM' && h === 12) h = 0;
    return `${String(h).padStart(2, '0')}:${String(min).padStart(2, '0')}:00`;
  }

  const open = to24(m[1], m[2]);
  const close = to24(m[3], m[4]);

  // If there are extra tokens beyond the time range, keep them as notes
  const leftover = raw.replace(timeRe, '').trim().replace(/^[,;-]+/, '').trim();
  return { open, close, notes: leftover || null };
}

/**
 * Extract state name from the city's country field.
 * "Himachal Pradesh, India" -> "Himachal Pradesh"
 * "India" -> null
 */
function extractState(countryField) {
  const parts = countryField.split(',').map(s => s.trim());
  if (parts.length > 1 && parts[parts.length - 1] === 'India') {
    return parts.slice(0, -1).join(', ');
  }
  return null;
}

// ---------------------------------------------------------------------------
// Main seed logic
// ---------------------------------------------------------------------------

async function seed() {
  console.log('=== TripSwipe Seed Script ===\n');

  // -----------------------------------------------------------------------
  // 1. Boot Strapi
  // -----------------------------------------------------------------------
  console.log('[1/6] Loading Strapi...');

  const { compileStrapi, createStrapi } = require('@strapi/core');
  const appContext = await compileStrapi();
  const app = await createStrapi(appContext).load();

  // Convenience aliases
  const db = app.db;

  console.log('  Strapi loaded.\n');

  // Helper: find or create a record using db.query ---------------------------
  async function findOrCreate(uid, filters, data) {
    const existing = await db.query(uid).findOne({ where: filters });
    if (existing) {
      return { entry: existing, created: false };
    }
    const entry = await db.query(uid).create({ data });
    return { entry, created: true };
  }

  // Helper: publish (for content-types with draftAndPublish) -----------------
  // In Strapi v5 with db.query, we set publishedAt directly
  async function publishEntry(uid, id) {
    try {
      await db.query(uid).update({
        where: { id },
        data: { publishedAt: new Date().toISOString() },
      });
    } catch {
      // Already published or not applicable
    }
  }

  // -----------------------------------------------------------------------
  // 2. Country
  // -----------------------------------------------------------------------
  console.log('[2/6] Seeding country...');
  const { entry: india, created: indiaCreated } = await findOrCreate(
    'api::country.country',
    { name: 'India' },
    { name: 'India', slug: 'india', code: 'IN' },
  );
  if (indiaCreated) {
    await publishEntry('api::country.country', india.id);
  }
  console.log(`  Country "India" ${indiaCreated ? 'CREATED' : 'already exists'}\n`);

  // -----------------------------------------------------------------------
  // 3. States
  // -----------------------------------------------------------------------
  console.log('[3/6] Seeding states...');
  const stateNames = [...new Set(cities.map(c => extractState(c.country)).filter(Boolean))];
  const stateMap = {}; // name -> strapi record

  for (const sName of stateNames) {
    const { entry, created } = await findOrCreate(
      'api::state.state',
      { name: sName },
      { name: sName, slug: slugify(sName), country: india.id },
    );
    stateMap[sName] = entry;
    console.log(`  State "${sName}" ${created ? 'CREATED' : 'exists'} (id=${entry.id})`);
  }
  console.log();

  // -----------------------------------------------------------------------
  // 4. Cities
  // -----------------------------------------------------------------------
  console.log('[4/6] Seeding cities...');
  const cityMap = {}; // mock id -> strapi record

  for (const c of cities) {
    const sName = extractState(c.country);
    const stateRef = sName ? stateMap[sName]?.id : undefined;

    const cityData = {
      name: c.name,
      slug: slugify(c.name),
      country: india.id,
      ...(stateRef ? { state: stateRef } : {}),
    };

    const { entry, created } = await findOrCreate(
      'api::city.city',
      { name: c.name },
      cityData,
    );
    if (created) {
      await publishEntry('api::city.city', entry.id);
    }
    cityMap[c.id] = entry;
    console.log(`  City "${c.name}" ${created ? 'CREATED' : 'exists'} (id=${entry.id})`);
  }
  console.log();

  // -----------------------------------------------------------------------
  // 5. Tags
  // -----------------------------------------------------------------------
  console.log('[5/6] Seeding tags...');
  const allTagNames = [...new Set(places.flatMap(p => p.tags))];
  const tagMap = {}; // name -> strapi record

  // Heuristic tag type classification
  const TAG_TYPE_MAP = {
    // themes
    'Must-See': 'theme', 'Must-Do': 'theme', 'Must-Try': 'theme', 'UNESCO': 'theme',
    'Traveler Favorite': 'theme', 'Unique Experience': 'theme', 'Offbeat': 'theme',
    'Family Fun': 'theme', 'Family-Friendly': 'theme', 'Romantic': 'theme',
    'Quick Stop': 'theme', 'Secluded': 'theme', 'Base': 'theme', 'Entertainment': 'theme',

    // activity_type
    'Photography': 'activity_type', 'Swimming': 'activity_type', 'Trekking': 'activity_type',
    'Adventure': 'activity_type', 'Water Sports': 'activity_type', 'Snorkeling': 'activity_type',
    'Paragliding': 'activity_type', 'Skiing': 'activity_type', 'Walking': 'activity_type',
    'Camping': 'activity_type', 'Yoga': 'activity_type', 'Shopping': 'activity_type',
    'Birdwatching': 'activity_type', 'Nightlife': 'activity_type', 'Dining': 'activity_type',
    'Market': 'activity_type',

    // vibe
    'Peaceful': 'vibe', 'Scenic': 'vibe', 'Relaxation': 'vibe', 'Thrilling': 'vibe',
    'Remote': 'vibe', 'Accessible': 'vibe', 'Sunset': 'vibe',

    // cuisine
    'Local Cuisine': 'cuisine', 'Bakery': 'cuisine', 'Cafe': 'cuisine', 'Cafes': 'cuisine',
    'Rooftop': 'cuisine', 'Seafood': 'cuisine', 'Organic': 'cuisine', 'Restaurant': 'cuisine',
    'Street Food': 'cuisine', 'Traditional': 'cuisine',

    // terrain
    'Nature': 'terrain', 'Beach': 'terrain', 'Lake': 'terrain', 'Island': 'terrain',
    'Wildlife': 'terrain', 'Marine Life': 'terrain', 'Snow': 'terrain',
    'Hot Springs': 'terrain', 'Glacier': 'terrain', 'Flowers': 'terrain',
    'Mountains': 'terrain', 'Mountain Pass': 'terrain', 'Viewpoint': 'terrain',
    'Gardens': 'terrain',

    // default to theme for the rest
    'Culture': 'theme', 'Historic': 'theme', 'Architecture': 'theme',
    'Monument': 'theme', 'Monastery': 'theme', 'Temple': 'theme',
    'Village': 'theme', 'City': 'theme', 'Hill Station': 'theme',
    'Wellness': 'vibe', 'Homestay': 'theme', 'Cultural Experience': 'theme',
    'Sacred': 'theme', 'High Altitude': 'terrain', 'Extreme Altitude': 'terrain',
    'Border': 'theme', 'Museum': 'theme', 'Accommodation': 'theme',
    'Local Culture': 'theme',
  };

  for (const tagName of allTagNames) {
    const tagType = TAG_TYPE_MAP[tagName] || 'theme';
    const { entry, created } = await findOrCreate(
      'api::tag.tag',
      { name: tagName },
      { name: tagName, slug: slugify(tagName), type: tagType },
    );
    tagMap[tagName] = entry;
    if (created) {
      console.log(`  Tag "${tagName}" CREATED (type=${tagType})`);
    }
  }
  console.log(`  ${allTagNames.length} tags processed.\n`);

  // -----------------------------------------------------------------------
  // 6. Places
  // -----------------------------------------------------------------------
  console.log('[6/6] Seeding places...');
  let createdCount = 0;
  let skippedCount = 0;

  for (const p of places) {
    // Idempotency check
    const existing = await db.query('api::place.place').findOne({
      where: { name: p.name },
    });
    if (existing) {
      skippedCount++;
      continue;
    }

    const cityEntry = cityMap[p.cityId];
    if (!cityEntry) {
      console.log(`  WARN: No city found for cityId="${p.cityId}", skipping "${p.name}"`);
      skippedCount++;
      continue;
    }

    const operatingHours = parseOperatingHours(p.openHours);
    const tagIds = p.tags
      .map(t => tagMap[t]?.id)
      .filter(Boolean);

    const placeData = {
      name: p.name,
      slug: slugify(p.name),
      category: mapCategory(p.category),
      subcategory: p.category,
      city: cityEntry.id,
      country: india.id,
      short_description: p.description,
      description: p.detailedDescription,
      rating: p.rating,
      area: p.area,
      duration_label: p.duration,
      cost_level: mapCostLevel(p.priceLevel),
      best_months: p.bestTime ? [p.bestTime] : [],
      popularity_score: popularityFromRating(p.rating),
      is_featured: p.rating >= 4.8,
      tags: tagIds,
      extra_attributes: {
        image_urls: p.images,
        mock_id: p.id,
      },
    };

    // Operating hours component
    if (operatingHours) {
      placeData.operating_hours = operatingHours;
    }

    try {
      const entry = await db.query('api::place.place').create({ data: placeData });
      await publishEntry('api::place.place', entry.id);
      createdCount++;
      console.log(`  + ${p.name} (${mapCategory(p.category)})`);
    } catch (err) {
      console.error(`  ERROR creating "${p.name}":`, err.message || err);
    }
  }

  console.log(`\n  Places: ${createdCount} created, ${skippedCount} skipped (already exist).`);
  console.log('\n=== Seed complete ===');

  process.exit(0);
}

// ---------------------------------------------------------------------------
// Run
// ---------------------------------------------------------------------------
seed().catch((err) => {
  console.error('Seed failed:', err);
  process.exit(1);
});
